import{_ as o,W as n,X as r,Z as i,$ as a,a0 as t,a1 as p,D as d}from"./framework-c9619a7b.js";const l={},s=i("h2",{id:"简介",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),a(" 简介")],-1),c=i("p",null,"Kopia是一个快速而安全的开源备份/还原工具，允许您创建加密的数据快照并将其保存到您选择的远程或云存储、网络附加存储或服务器，或本地计算机上。 Kopia不会“映像”整个计算机。相反，Kopia允许您备份/还原您认为重要或关键的任何文件/目录。",-1),h=i("p",null,"Kopia有CLI（命令行界面）和GUI（图形用户界面）版本，使其成为高级用户和普通用户的完美工具。您可以阅读有关Kopia独特功能的更多信息，包括压缩，去重，端到端“零知识”加密和纠错，以更好地了解Kopia的工作原理。",-1),g={href:"https://github.com/kopia/kopia",target:"_blank",rel:"noopener noreferrer"},f=i("br",null,null,-1),_={href:"https://kopia.io/docs/",target:"_blank",rel:"noopener noreferrer"},b=i("h2",{id:"安装",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#安装","aria-hidden":"true"},"#"),a(" 安装")],-1),u={href:"https://kopia.io/docs/installation/",target:"_blank",rel:"noopener noreferrer"},m=p('<h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2><h3 id="选择备份存储位置" tabindex="-1"><a class="header-anchor" href="#选择备份存储位置" aria-hidden="true">#</a> 选择备份存储位置</h3><p>支持本地存储、SFTP、WebDAV、谷歌云、Amazon S3等多种存储源.</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523130909.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="创建快照" tabindex="-1"><a class="header-anchor" href="#创建快照" aria-hidden="true">#</a> 创建快照</h3><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523131325.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>指定需要备份的目录路径,并配置备份策略</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523132239.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="配置备份策略" tabindex="-1"><a class="header-anchor" href="#配置备份策略" aria-hidden="true">#</a> 配置备份策略</h3><p>可以在策略(Policy)标签页下进行设置:</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523131505.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>可以从以下多个维度进行策略配置,包括快照保留、文件、压缩算法、调度等.</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523131410.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="还原" tabindex="-1"><a class="header-anchor" href="#还原" aria-hidden="true">#</a> 还原</h3><p>在快照标签页下点开一个路径,可以看到该路径的快照历史</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523131710.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>点开其中一个快照历史,可以选择将其挂载到本地或者恢复到指定目录</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523131725.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',18);function k(x,v){const e=d("ExternalLinkIcon");return n(),r("div",null,[s,c,h,i("p",null,[a("Github: "),i("a",g,[a("https://github.com/kopia/kopia"),t(e)]),f,a(" 文档: "),i("a",_,[a("https://kopia.io/docs/"),t(e)])]),b,i("p",null,[a("参考: "),i("a",u,[a("https://kopia.io/docs/installation/"),t(e)])]),m])}const z=o(l,[["render",k],["__file","备份工具Kopia安装与使用教程.html.vue"]]);export{z as default};
